#include <stdio.h>
#include <stdlib.h>

int lower_bound(int *arr, int size, int val){
    int l=0, r=size;
    while(l<r){
        int m=(l+r)/2;
        if(arr[m]>=val) r=m; else l=m+1;
    }
    return l;
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int *a=malloc(N*sizeof(int));
        for(int i=0;i<N;i++) scanf("%d",&a[i]);
        int *L=malloc(N*sizeof(int));
        int *tail=malloc(N*sizeof(int));
        int sz=0;
        for(int i=0;i<N;i++){
            int pos=lower_bound(tail,sz,a[i]);
            tail[pos]=a[i];
            if(pos==sz) sz++;
            L[i]=pos+1;
        }
        // compute decreasing lengths using reversed array
        int *R=malloc(N*sizeof(int));
        sz=0;
        for(int i=N-1;i>=0;i--){
            int pos=lower_bound(tail,sz,a[i]);
            tail[pos]=a[i];
            if(pos==sz) sz++;
            R[i]=pos+1;
        }
        int ans=0;
        for(int i=0;i<N;i++){
            int cur=L[i]+R[i]-1;
            if(cur>ans) ans=cur;
        }
        printf("%d\n",ans);
        free(a); free(L); free(R); free(tail);
    }
    return 0;
}

