        for(int i=0;i<N;i++){
            auto it=lower_bound(tail.begin(),tail.end(),a[i]);
            int pos=it-tail.begin();
            if(it==tail.end()) tail.push_back(a[i]); else *it=a[i];
            L[i]=pos+1;
        }
        vector<int> R(N);
        tail.clear();
        for(int i=N-1;i>=0;i--){
            auto it=lower_bound(tail.begin(),tail.end(),a[i]);
            int pos=it-tail.begin();
            if(it==tail.end()) tail.push_back(a[i]); else *it=a[i];
            R[i]=pos+1;
        }
        int ans=0;
        for(int i=0;i<N;i++) ans=max(ans, L[i]+R[i]-1);
        cout<<ans<<"\n";
    }
    return 0;
}

