import java.io.*;
import java.util.*;
public class Main {
    static int lowerBound(int[] arr, int size, int val){
        int l=0, r=size;
        while(l<r){
            int m=(l+r)>>>1;
            if(arr[m]>=val) r=m; else l=m+1;
        }
        return l;
    }
    public static void main(String[] args) throws Exception{
        FastScanner fs=new FastScanner(System.in);
        int T=fs.nextInt();
        StringBuilder sb=new StringBuilder();
        while(T-- >0){
            int N=fs.nextInt();
            int[] a=new int[N];
            for(int i=0;i<N;i++) a[i]=fs.nextInt();
            int[] L=new int[N];
            int[] tail=new int[N];
            int sz=0;
            for(int i=0;i<N;i++){
                int pos=lowerBound(tail,sz,a[i]);
                tail[pos]=a[i];
                if(pos==sz) sz++;
                L[i]=pos+1;
            }
            int[] R=new int[N];
            sz=0;
            for(int i=N-1;i>=0;i--){
                int pos=lowerBound(tail,sz,a[i]);
                tail[pos]=a[i];
                if(pos==sz) sz++;
                R[i]=pos+1;
            }
            int ans=0;
            for(int i=0;i<N;i++) ans=Math.max(ans, L[i]+R[i]-1);
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
    static class FastScanner{
        private final InputStream in;
        private final byte[] buffer=new byte[1<<16];
        private int ptr=0, len=0;
        FastScanner(InputStream in){this.in=in;}
        private int read() throws IOException{
            if(ptr>=len){
                len=in.read(buffer);
                ptr=0;
                if(len<=0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException{
            int c, sign=1, val=0;
            do{c=read();}while(c<=32 && c!=-1);
            if(c=='-'){sign=-1; c=read();}
            while(c>32 && c!=-1){val=val*10+(c-'0'); c=read();}
            return val*sign;
        }
    }
}

