const fs=require('fs');
const input=fs.readFileSync(0,'utf-8').trim().split(/\s+/).map(Number);
let idx=0;
const T=input[idx++]||0;
let outputs=[];
function lisLengths(arr){
  const tail=[];
  const res=new Array(arr.length);
  for(let i=0;i<arr.length;i++){
    const x=arr[i];
    // binary search lower_bound
    let l=0, r=tail.length;
    while(l<r){
      const m=(l+r)>>1;
      if(tail[m]>=x) r=m; else l=m+1;
    }
    if(l===tail.length) tail.push(x); else tail[l]=x;
    res[i]=l+1;
  }
  return res;
}
for(let t=0;t<T;t++){
  const N=input[idx++];
  const a=input.slice(idx, idx+N); idx+=N;
  const L=lisLengths(a);
  const R=lisLengths(a.slice().reverse()).reverse();
  let ans=0;
  for(let i=0;i<N;i++) ans=Math.max(ans, L[i]+R[i]-1);
  outputs.push(String(ans));
}
console.log(outputs.join('\n'));
